import { ChangeDetectionStrategy, Component, computed, input } from '@angular/core';

import { mergeClasses } from '../../utils/merge-classes';
import {
  tableBodyVariants,
  tableCaptionVariants,
  tableCellVariants,
  tableFooterVariants,
  tableHeaderVariants,
  tableHeadVariants,
  tableRowVariants,
  tableScrollVariants,
  tableVariants,
  type TableSizeVariants,
  type TableVariantVariants,
} from './table.variants';

@Component({
  selector: 'n-table, table[n-table]',
  standalone: true,
  template: `<ng-content />`,
  changeDetection: ChangeDetectionStrategy.OnPush,
  host: { '[class]': 'classes()' },
  exportAs: 'nTable',
})
export class TableComponent {
  readonly nVariant = input<TableVariantVariants>('default');
  readonly nSize = input<TableSizeVariants>('default');
  readonly nClass = input<string>('');

  protected readonly classes = computed(() =>
    mergeClasses(
      tableVariants({ nVariant: this.nVariant(), nSize: this.nSize() }),
      this.nClass(),
    ),
  );
}

@Component({
  selector: 'n-table-header, thead[n-table-header]',
  standalone: true,
  template: `<ng-content />`,
  changeDetection: ChangeDetectionStrategy.OnPush,
  host: { '[class]': 'classes()' },
  exportAs: 'nTableHeader',
})
export class TableHeaderComponent {
  readonly nClass = input<string>('');

  protected readonly classes = computed(() => mergeClasses(tableHeaderVariants(), this.nClass()));
}

@Component({
  selector: 'n-table-body, tbody[n-table-body]',
  standalone: true,
  template: `<ng-content />`,
  changeDetection: ChangeDetectionStrategy.OnPush,
  host: { '[class]': 'classes()' },
  exportAs: 'nTableBody',
})
export class TableBodyComponent {
  readonly nClass = input<string>('');

  protected readonly classes = computed(() => mergeClasses(tableBodyVariants(), this.nClass()));
}

@Component({
  selector: 'n-table-footer, tfoot[n-table-footer]',
  standalone: true,
  template: `<ng-content />`,
  changeDetection: ChangeDetectionStrategy.OnPush,
  host: { '[class]': 'classes()' },
  exportAs: 'nTableFooter',
})
export class TableFooterComponent {
  readonly nClass = input<string>('');

  protected readonly classes = computed(() => mergeClasses(tableFooterVariants(), this.nClass()));
}

@Component({
  selector: 'n-table-row, tr[n-table-row]',
  standalone: true,
  template: `<ng-content />`,
  changeDetection: ChangeDetectionStrategy.OnPush,
  host: { '[class]': 'classes()' },
  exportAs: 'nTableRow',
})
export class TableRowComponent {
  readonly nClass = input<string>('');

  protected readonly classes = computed(() => mergeClasses(tableRowVariants(), this.nClass()));
}

@Component({
  selector: 'n-table-head, th[n-table-head]',
  standalone: true,
  template: `<ng-content />`,
  changeDetection: ChangeDetectionStrategy.OnPush,
  host: { '[class]': 'classes()' },
  exportAs: 'nTableHead',
})
export class TableHeadComponent {
  readonly nClass = input<string>('');

  protected readonly classes = computed(() => mergeClasses(tableHeadVariants(), this.nClass()));
}

@Component({
  selector: 'n-table-cell, td[n-table-cell]',
  standalone: true,
  template: `<ng-content />`,
  changeDetection: ChangeDetectionStrategy.OnPush,
  host: { '[class]': 'classes()' },
  exportAs: 'nTableCell',
})
export class TableCellComponent {
  readonly nClass = input<string>('');

  protected readonly classes = computed(() => mergeClasses(tableCellVariants(), this.nClass()));
}

@Component({
  selector: 'n-table-caption, caption[n-table-caption]',
  standalone: true,
  template: `<ng-content />`,
  changeDetection: ChangeDetectionStrategy.OnPush,
  host: { '[class]': 'classes()' },
  exportAs: 'nTableCaption',
})
export class TableCaptionComponent {
  readonly nClass = input<string>('');

  protected readonly classes = computed(() =>
    mergeClasses(tableCaptionVariants(), this.nClass()),
  );
}

@Component({
  selector: 'n-table-scroll',
  standalone: true,
  template: `<ng-content />`,
  changeDetection: ChangeDetectionStrategy.OnPush,
  host: {
    '[class]': 'classes()',
    // Scrollable region must be keyboard-focusable so it can be scrolled with arrow keys (WCAG 2.1.1).
    tabindex: '0',
    '[attr.role]': 'nLabel() ? "region" : null',
    '[attr.aria-label]': 'nLabel() || null',
  },
  exportAs: 'nTableScroll',
})
export class TableScrollComponent {
  readonly nClass = input<string>('');
  readonly nLabel = input<string>('');

  protected readonly classes = computed(() => mergeClasses(tableScrollVariants(), this.nClass()));
}

import { cva, type VariantProps } from 'class-variance-authority';

export const tableVariants = cva(
  'w-full caption-bottom text-sm',
  {
    variants: {
      nVariant: {
        default: '',
        striped: '[&_tbody_tr:nth-child(odd)]:bg-muted/50',
        bordered: 'border border-border [&_th]:border [&_td]:border',
      },
      nSize: {
        default: '',
        compact: '[&_td]:py-1.5 [&_th]:py-1.5 [&_td]:px-3 [&_th]:px-3 text-xs',
        comfortable: '[&_td]:py-4 [&_th]:py-4',
      },
    },
    defaultVariants: {
      nVariant: 'default',
      nSize: 'default',
    },
  },
);

export const tableHeaderVariants = cva('[&_tr]:border-b');

export const tableBodyVariants = cva('[&_tr:last-child]:border-0');

export const tableFooterVariants = cva('border-t bg-muted/50 font-medium [&>tr]:last:border-b-0');

export const tableRowVariants = cva(
  'border-b transition-colors hover:bg-muted/50 data-[state=selected]:bg-muted',
);

export const tableHeadVariants = cva(
  'h-10 px-4 text-left align-middle font-medium text-muted-foreground [&:has([role=checkbox])]:pr-0 *:[[role=checkbox]]:translate-y-0.5',
);

export const tableCellVariants = cva(
  'p-4 align-middle [&:has([role=checkbox])]:pr-0 *:[[role=checkbox]]:translate-y-0.5',
);

export const tableCaptionVariants = cva('mt-4 text-sm text-muted-foreground');

export const tableScrollVariants = cva(
  'relative w-full overflow-x-auto focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-2 rounded-md',
);

export type TableVariants = VariantProps<typeof tableVariants>;
export type TableSizeVariants = NonNullable<TableVariants['nSize']>;
export type TableVariantVariants = NonNullable<TableVariants['nVariant']>;

